"""
    get_auto_merging_preview(conflict_resolution, consolidation, domain_name)
    get_auto_merging_preview(conflict_resolution, consolidation, domain_name, params::Dict{String,<:Any})

Tests the auto-merging settings of your Identity Resolution Job without merging your data.
It randomly selects a sample of matching groups from the existing matching results, and
applies the automerging settings that you provided. You can then view the number of profiles
in the sample, the number of matches, and the number of profiles identified to be merged.
This enables you to evaluate the accuracy of the attributes in your matching list.

You can't view which profiles are matched and would be merged.

!!! important
    We strongly recommend you use this API to do a dry run of the automerging process before
    running the Identity Resolution Job. Include **at least** two matching attributes. If
    your matching list includes too few attributes (such as only `FirstName` or only
    `LastName`), there may be a large number of matches. This increases the chances of
    erroneous merges.

# Arguments

- `conflict_resolution`: How the auto-merging process should resolve conflicts between
  different profiles.
- `consolidation`: A list of matching attributes that represent matching criteria.
- `domain_name`: The unique name of the domain.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"MinAllowedConfidenceScoreForMerging"`: Minimum confidence score required for profiles
  within a matching group to be merged during the auto-merge process.
"""
function get_auto_merging_preview end

function get_auto_merging_preview(
    ConflictResolution,
    Consolidation,
    DomainName;
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return customer_profiles(
        "POST",
        "/domains/$(DomainName)/identity-resolution-jobs/auto-merging-preview",
        Dict{String,Any}(
            "ConflictResolution" => ConflictResolution, "Consolidation" => Consolidation
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function get_auto_merging_preview(
    ConflictResolution,
    Consolidation,
    DomainName,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return customer_profiles(
        "POST",
        "/domains/$(DomainName)/identity-resolution-jobs/auto-merging-preview",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "ConflictResolution" => ConflictResolution,
                    "Consolidation" => Consolidation,
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

